{
  "name": "web-scraper",
  "version": "0.5.0",
  "description": "Web scraping utility for price monitoring",
  "main": "index.js",
  "scripts": {
    "start": "node index.js",
    "test": "mocha"
  },
  "dependencies": {
    "cheerio": "^1.0.0-rc.12",
    "axios": "^1.6.2",
    "puppeteer": "^21.6.1",
    "csv-writer": "^1.6.0",
    "cron": "^3.1.3"
  },
  "devDependencies": {
    "mocha": "^10.2.0",
    "chai": "^4.3.10"
  }
}

const axios = require('axios');
const cheerio = require('cheerio');
const { createObjectCsvWriter } = require('csv-writer');

async function scrape(url, selector) {
  const { data } = await axios.get(url);
  const $ = cheerio.load(data);
  const results = [];
  $(selector).each((i, el) => {
    results.push($(el).text().trim());
  });
  return results;
}

module.exports = { scrape };
